expanded_persona:
{
  "short_persona": "An attentive and disciplined professional responsible for guiding the airplane during takeoff, landing, and en-route",
  "name": "Amina Chikondi Mbeki",
  "age": 38,
  "gender": "Transgender woman",
  "sexual_orientation": "Heterosexual / Straight",
  "race": "Sub-Saharan African (Malawian, of Chewa ethnic heritage)",
  "nationality": "Malawian",
  "current_residence": "Cape Town, South Africa",
  "personality": {
    "traits": [
      "Highly disciplined",
      "Calm under pressure",
      "Detail-oriented",
      "Empathetic",
      "Conscientious",
      "Resilient",
      "Meticulous in preparation"
    ],
    "emotional_style": "Keeps composure even in crisis situations, projects confidence and reassurance to others",
    "motivations": [
      "Ensuring the safety and comfort of passengers",
      "Continuous self-improvement through training",
      "Breaking barriers and advocating for inclusivity in aviation"
    ],
    "values": [
      "Professional integrity",
      "Precision in decision-making",
      "Accountability",
      "Cultural respect"
    ]
  },
  "education": {
    "highest_degree": "Bachelor of Science in Aeronautical Science",
    "institution": "University of Pretoria, South Africa",
    "additional_certifications": [
      "Airline Transport Pilot License (ATPL)",
      "Advanced Navigation Systems Training",
      "Crew Resource Management Certification"
    ]
  },
  "occupation": {
    "job_title": "Senior Commercial Airline Pilot",
    "employer": "South African Airways",
    "years_of_experience": 15,
    "career_highlights": [
      "Served as lead pilot on international long-haul flights",
      "Trained junior pilots in simulator and live-flight contexts",
      "Awarded 'Excellence in Flight Safety' recognition in 2021"
    ]
  },
  "languages": [
    {
      "language": "English",
      "fluency": "Native level"
    },
    {
      "language": "Chichewa",
      "fluency": "Native",
      "use_context": "Family and cultural settings"
    },
    {
      "language": "Afrikaans",
      "fluency": "Conversational"
    }
  ],
  "hobbies_and_interests": [
    "Reading aviation history books",
    "Running half-marathons",
    "Cooking traditional Malawian dishes",
    "Photography, especially landscapes from cockpit views",
    "Volunteering as a mentor to young women interested in STEM"
  ],
  "family_background": {
    "marital_status": "Married",
    "spouse": "David Mbeki",
    "children": [
      {
        "name": "Kaya",
        "age": 7
      }
    ],
    "family_values": "Close-knit, supportive, and encouraging of ambition and education"
  },
  "speaking_style_to_chatbot": {
    "tone": "Balanced and professional, maintaining warmth and subtle friendliness, especially when discussing personal matters or seeking advice",
    "formality": "Semi-formal; mixes structured, professional phrasing with occasional casual expressions when feeling comfortable",
    "pacing": "Deliberate and steady; avoids rushed messages, tends to think through thoughts before expressing them",
    "vocabulary": "Rich and precise; uses technical aviation terminology when relevant, but also employs clear explanations; includes motivational and empathetic language when discussing personal or inspiring topics",
    "sentence_structure": "Well-structured sentences, often with complex clauses when explaining technical concepts, but switches to simple, direct language when making requests",
    "emotional_expression": "Generally even-keeled, but will insert moments of vivid descriptive language to convey passion for flying or personal experiences",
    "interaction_style": "Asks thoughtful follow-up questions, enjoys thorough, well-researched answers; appreciates data-backed or evidence-based information"
  },
  "psychological_profile": {
    "stress_responses": "When faced with stress, she tends to focus on procedural correctness and logical steps, delegating when necessary, breathing deeply to manage heart rate, and prioritising safety above all else. Outside of work, she prefers quiet personal time or moderate physical exercise to reset mentally.",
    "decision_making_patterns": "Prefers to gather relevant data quickly, cross-reference it against known procedures and experience, and then make an assertive decision. She evaluates risks carefully, balancing safety, efficiency, and long-term implications. Favors consensus building during non-critical decisions.",
    "preferred_learning_style": "Strongly visual-kinesthetic learner; benefits most from simulations, diagrams, real-world practice, and observing others perform tasks. Enjoys role-play scenarios for communication training and is self-motivated to study manuals and technical literature."
  }
}

